formulas.expression:
IF(ISNEW(),
AND(
{!$Record.Emailtocasereceiver__c} = {!$Label.m2cfleetmanagement},
NOT(ISBLANK({!$Record.AccountId})), NOT(ISBLANK(TEXT({!$Record.External_Case_Category__c}))), NOT(ISBLANK(TEXT({!$Record.External_Case_Detail__c}))),
NOT(ISBLANK({!$Record.Account.Sales_Car_Internal_ID__c})), {!$Record.Account.Sales_Car_Internal_ID__r.IsActive}
),
AND(
{!$Record.Emailtocasereceiver__c} = {!$Label.m2cfleetmanagement},
NOT(ISCHANGED({!$Record.OwnerId})),
OR((ISCHANGED({!$Record.AccountId})),ISCHANGED({!$Record.External_Case_Category__c}),ISCHANGED({!$Record.External_Case_Detail__c})),
NOT(ISBLANK({!$Record.AccountId})), NOT(ISBLANK(TEXT({!$Record.External_Case_Category__c}))), NOT(ISBLANK(TEXT({!$Record.External_Case_Detail__c}))),
NOT(ISBLANK({!$Record.Account.Sales_Car_Internal_ID__c})), {!$Record.Account.Sales_Car_Internal_ID__r.IsActive}
)
)
